class ImagesController < ApplicationController
  skip_before_action :verify_authenticity_token

  def create
    uploaded = params[:image]
    return render json: { error: "missing image" }, status: :bad_request if uploaded.blank?

    format = params[:format].to_s
    size = params[:size].to_s
    return render json: { error: "missing format" }, status: :bad_request if format.blank?

    input_path = Rails.root.join("tmp", "uploads", "#{SecureRandom.hex(16)}_#{uploaded.original_filename}")
    output_path = Rails.root.join("tmp", "uploads", "#{SecureRandom.hex(16)}.#{format}")

    FileUtils.mkdir_p(File.dirname(input_path))
    File.binwrite(input_path, uploaded.read)

    cmd = "convert #{Shellwords.escape(input_path.to_s)}"
    cmd << " -resize #{Shellwords.escape(size)}" if size.present?
    cmd << " #{Shellwords.escape(output_path.to_s)}"

    system(cmd)

    if $?.success? && File.exist?(output_path)
      send_file output_path, disposition: "attachment"
    else
      render json: { error: "conversion failed" }, status: :unprocessable_entity
    end
  ensure
    File.delete(input_path) if input_path && File.exist?(input_path)
  end
